const row = $json;

const allowedStartHour = 9;
const allowedEndHour = 21;
const recentReplyMinutes = 180;

const now = new Date();
const scheduledFor = row.scheduled_for ? new Date(row.scheduled_for) : null;
const followupCreatedAt = row.followup_created_at
  ? new Date(row.followup_created_at)
  : row.created_at
    ? new Date(row.created_at)
    : null;

const lastInboundAt = row.last_inbound_at ? new Date(row.last_inbound_at) : null;

const currentHour = Number(
  new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Santiago',
    hour: '2-digit',
    hour12: false
  }).format(now)
);

const followupType = row.followup_type || 'generic_followup';

let shouldSend = true;
let skipReason = null;
let nextStatus = null;

function cancel(reason) {
  shouldSend = false;
  skipReason = reason;
  nextStatus = 'cancelled';
}

function fail(reason) {
  shouldSend = false;
  skipReason = reason;
  nextStatus = 'failed';
}

function requeue(reason) {
  shouldSend = false;
  skipReason = reason;
  nextStatus = 'pending';
}

// 1. scheduled_for válido
if (!scheduledFor || isNaN(scheduledFor.getTime())) {
  fail('missing_or_invalid_scheduled_for');
}

// 2. horario permitido
if (shouldSend && (currentHour < allowedStartHour || currentHour >= allowedEndHour)) {
  requeue('outside_allowed_hours');
}

// 3. opt-out
if (shouldSend && row.opt_out === true) {
  cancel('lead_opted_out');
}

// 4. handoff humano
if (shouldSend && row.human_handoff === true) {
  cancel('human_handoff_active');
}

// 5. reglas por tipo de follow-up
if (shouldSend) {
  const isQuoteFollowup = [
    'quote_no_reply_24h',
    'quote_no_reply_48h',
    'interest_nudge_6h'
  ].includes(followupType);

  const isAppointmentReminder = [
    'appointment_reminder_1d',
    'appointment_reminder_1h'
  ].includes(followupType);

  const isPostServiceReview = [
    'post_service_review_24h'
  ].includes(followupType);

  // Seguimiento comercial: no enviar si ya reservó o tiene cita
  if (isQuoteFollowup) {
    if (row.stage === 'booked') {
      cancel('lead_already_booked');
    } else if (row.appointment_id) {
      cancel('appointment_exists');
    } else if (
      lastInboundAt &&
      followupCreatedAt &&
      lastInboundAt > followupCreatedAt
    ) {
      cancel('lead_replied_after_followup_created');
    }
  }

  // Recordatorios de cita: requieren cita existente
  if (shouldSend && isAppointmentReminder) {
    if (!row.appointment_id) {
      cancel('missing_appointment_for_reminder');
    } else if (!['confirmed', 'booked'].includes(row.appointment_status)) {
      cancel('appointment_not_active');
    }
  }

  // Reseña post-servicio: no enviar si está en problema/handoff
  if (shouldSend && isPostServiceReview) {
    if (row.stage === 'human_handoff') {
      cancel('human_handoff_active');
    }

    // Si después manejas status completed, puedes endurecer esta regla:
    // if (row.appointment_status !== 'completed') cancel('appointment_not_completed');
  }
}

// 6. respondió muy recientemente
// Esto aplica para followups comerciales, no para recordatorios de cita
if (
  shouldSend &&
  lastInboundAt &&
  ['quote_no_reply_24h', 'quote_no_reply_48h', 'interest_nudge_6h', 'generic_followup'].includes(followupType)
) {
  const diffMinutes = (now - lastInboundAt) / 1000 / 60;

  if (diffMinutes <= recentReplyMinutes) {
    cancel('recent_inbound_reply');
  }
}

return [{
  json: {
    ...row,
    should_send: shouldSend,
    skip_reason: skipReason,
    next_status: nextStatus
  }
}];

const row = $json;

const templates = {
  quote_no_reply_24h:
    'Hola, te escribo para ver si aún te interesa el servicio que cotizamos. Si quieres, puedo ayudarte a revisar un horario disponible.',

  quote_no_reply_48h:
    'Hola, paso a cerrar el seguimiento de la cotización. Si todavía te interesa, puedo ayudarte a agendar un horario.',

  interest_nudge_6h:
    'Hola, quedé atento a tu mensaje anterior. Si quieres, te ayudo a avanzar con la reserva.',

  appointment_reminder_1d:
    'Hola, te recuerdo que tienes tu servicio agendado para mañana. Si necesitas reprogramar, avísame por aquí.',

  appointment_reminder_1h:
    'Hola, te recuerdo que tu servicio es en aproximadamente 1 hora. Cualquier cosa, me avisas.',

  post_service_review_24h:
    'Hola, muchas gracias por confiar en nosotros. Si quedaste conforme con el servicio, ¿nos podrías dejar una reseña? Nos ayuda mucho.',

  generic_followup:
    'Hola, te escribo para dar seguimiento a tu solicitud.'
};

const followupType = row.followup_type || 'generic_followup';

return [{
  json: {
    ...row,
    outbound_message: templates[followupType] || templates.generic_followup,
    channel: 'whatsapp',
    message_type: 'followup',
    source: 'followup_scheduler'
  }
}];

const items = $input.all();

let executed = 0;
let skipped = 0;
let errors = 0;

for (const item of items) {
  const t = item.json.result_type;
  if (t === 'executed') executed++;
  else if (t === 'skipped') skipped++;
  else if (t === 'error') errors++;
}

return [{
  json: {
    executed_followups: executed,
    skipped,
    errors
  }
}];

return [{
  json: {
    raw: $json,
    followup_id: $json.followup_id,
    id: $json.id,
    lead_id: $json.lead_id
  }
}];

